// ========================================
// JS PER N8N - FORMATTA RISPOSTA GET_PROGRESS
// Input: stakeholder document da MongoDB
// Output: risposta per webhook frontend
// ========================================

const stakeholder = $input.first().json.stakeholder;

// Estrai i moduli soft skills (o usa default se non esistono)
const softSkillsModules = stakeholder.professional_profile?.soft_skills_modules || {
  modulo1: { completed: false, date: null, time: null, results: null, timestamp: null },
  modulo2: { completed: false, date: null, time: null, results: null, timestamp: null },
  modulo3: { completed: false, date: null, time: null, results: null, timestamp: null },
  modulo4: { completed: false, date: null, time: null, results: null, timestamp: null }
};

// Calcola quanti moduli sono completati
const completedCount = Object.values(softSkillsModules)
  .filter(m => m.completed === true)
  .length;

// Calcola percentuale (0, 25, 50, 75, 100)
const completionPercentage = (completedCount / 4) * 100;

// Ritorna la risposta per il frontend
return [{
  json: {
    success: true,
    modules_completed: softSkillsModules,
    completion_percentage: completionPercentage,
    timestamp: new Date().toISOString()
  }
}];

/**
 * PREPARA RISPOSTA PER FRONTEND - N8N COMPATIBLE
 * Restituisce solo i dati essenziali per il respond
 */

const items = $input.all();


const results = items.map(item => {
    const data = item.json;
    const moduleId = data.body.module_id; 
    const moduleEvaluation = data.ModuleEvaluation;
    const stakeholder = data.stakeholder;
    const now = new Date().toISOString();

    // Estrai vat e chat_id in modo sicuro
    const vatNumber = stakeholder?.owner_data_ref?.vat_number || data.body?.vat;
    const chatId = stakeholder?.owner_data_ref?.chat_id || data.body?.user_id;

    // 🔥 PREPARA SOLO LA RISPOSTA PER IL FRONTEND
    return {
        json: {
            success: true,
            module_id: moduleId,
            vat_number: vatNumber,
            chat_id: chatId,
            completion_date: now,
            evaluation: {
                PP: moduleEvaluation.PP,
                CP: moduleEvaluation.CP,
                PN: moduleEvaluation.PN,
                CN: moduleEvaluation.CN,
                Valutazione_Tempi: moduleEvaluation.Valutazione_Tempi,
                Analisi_Strategica: moduleEvaluation.Analisi_Strategica,
                Impatto_Business: moduleEvaluation.Impatto_Business,
                Consigli_Operativi: moduleEvaluation.Consigli_Operativi
            }
        }
    };
});

return results;

/**
 * SOFT SKILLS MODULE UPDATER - N8N COMPATIBLE
 * Aggiorna lo stakeholder_profile con i risultati della valutazione del modulo
 */

// 🔥 VERSIONE N8N - Usa $input.all() per ricevere i dati
const items = $input.all();


// Processa ogni item
const results = items.map(item => {
    const data = item.json;
    const moduleId = data.body.module_id; 
    // Estrai i dati
    const moduleEvaluation = data.ModuleEvaluation;
    const stakeholder = data.stakeholder;

    // 🔥 SAFE INITIALIZATION - Crea struttura se non esiste
    if (!stakeholder.professional_profile) {
        stakeholder.professional_profile = {};
    }

    if (!stakeholder.professional_profile.soft_skills_modules) {
        stakeholder.professional_profile.soft_skills_modules = {
            modulo1: { completed: false, date: null, time: null, results: null, timestamp: null },
            modulo2: { completed: false, date: null, time: null, results: null, timestamp: null },
            modulo3: { completed: false, date: null, time: null, results: null, timestamp: null },
            modulo4: { completed: false, date: null, time: null, results: null, timestamp: null }
        };
    }

    // Timestamp attuale
    const now = new Date().toISOString();

    // 🔥 AGGIORNA IL MODULO SPECIFICO
    stakeholder.professional_profile.soft_skills_modules[moduleId] = {
        completed: true,
        completion_date: now,
        evaluation: {
            PP: moduleEvaluation.PP,
            CP: moduleEvaluation.CP,
            PN: moduleEvaluation.PN,
            CN: moduleEvaluation.CN,
            Valutazione_Tempi: moduleEvaluation.Valutazione_Tempi,
            Analisi_Strategica: moduleEvaluation.Analisi_Strategica,
            Impatto_Business: moduleEvaluation.Impatto_Business,
            Consigli_Operativi: moduleEvaluation.Consigli_Operativi
        }
    };

    // 🔥 AGGIORNA METADATA
    if (!stakeholder.metadata) {
        stakeholder.metadata = {};
    }
    stakeholder.metadata.last_updated = now;


    // 🔥 RITORNA ENTRAMBI: stakeholder aggiornato
    return {
        json: {
            stakeholder: stakeholder,
            module_id: moduleId,
            vat_number: stakeholder.owner_data_ref.vat_number,
            chat_id: stakeholder.owner_data_ref.chat_id
        }
    };
});

return results;

