/**
 * PREPARA RISPOSTA PER FRONTEND
 * Restituisce solo i dati essenziali per il respond
 */
const stakeholder = $input.first().json.stakeholder;
// Estrai l'analisi completa che hai appena salvato
const profile = stakeholder.professional_profile?.soft_skills_complete_profile || {};

// Risposta al frontend
return {
  json: {
    success: true,
    action: "get_analysis",
    timestamp: new Date().toISOString(),
    data: {
      summary: profile.summary || {},
      strengths: profile.strengths || [],
      areas_to_improve: profile.areas_to_improve || [],
      recommended_videos: profile.recommended_videos || [],
      stats: profile.stats || {}
    }
  }
};

/**
 * PREPARA RISPOSTA PER FRONTEND
 * Restituisce solo i dati essenziali per il respond
 */
const stakeholder = $input.first().json.stakeholder;
// Estrai l'analisi completa che hai appena salvato
const profile = stakeholder.professional_profile?.soft_skills_complete_profile || {};

// Risposta al frontend
return {
  json: {
    success: true,
    action: "get_analysis",
    timestamp: new Date().toISOString(),
    data: {
      summary: profile.summary || {},
      strengths: profile.strengths || [],
      areas_to_improve: profile.areas_to_improve || [],
      recommended_videos: profile.recommended_videos || [],
      stats: profile.stats || {}
    }
  }
};

/**
 * PREPARA RISPOSTA PER FRONTEND dopo track_video_completion
 * Restituisce le 2 sezioni aggiornate + learning_history
 */
const professional_profile = $input.first().json.stakeholder.professional_profile;
const behavioral_profile = $input.first().json.stakeholder.behavioral_profile;

// Estrai learning_history e soft_skills_complete_profile
const learningHistory = professional_profile?.learning_history || null;
const profile = professional_profile?.soft_skills_complete_profile || {};

return {
  json: {
    success: true,
    action: "track_video_completion",
    timestamp: new Date().toISOString(),
    data: {
      // Dati per complete-profile (se user vuole vedere subito l'aggiornamento)
      summary: profile.summary || {},
      strengths: profile.strengths || [],
      areas_to_improve: profile.areas_to_improve || [],
      recommended_videos: profile.recommended_videos || [],
      stats: profile.stats || {},
      learning_history: learningHistory,
      professional_profile: professional_profile,
      behavioral_profile: behavioral_profile
    }
  }
};

